class SecureRedisClient:
    """Secure Redis client that enforces TLS connections."""

    def __init__(self):
        self._client: Optional[redis.Redis] = None
        self._sentinel: Optional[Sentinel] = None

    def _validate_tls_config(self):
        """Validate that TLS configuration is properly set."""
        if not os.path.exists(REDIS_SSL_CA_CERTS):
            raise FileNotFoundError(
                f"Redis SSL CA certificate not found: {REDIS_SSL_CA_CERTS}"
            )
        logger.info("TLS configuration validated successfully")

    def connect(self) -> redis.Redis:
        """Establish a secure TLS connection to Redis."""
        if self._client is not None:
            try:
                self._client.ping()
                return self._client
            except (redis.ConnectionError, redis.TimeoutError):
                logger.warning("Lost connection to Redis, reconnecting...")
                self._client = None

        self._validate_tls_config()

        ssl_kwargs = {
            "ssl": True,
            "ssl_ca_certs": REDIS_SSL_CA_CERTS,
            "ssl_cert_reqs": "required",
        }

        # Add client certificate if available
        if os.path.exists(REDIS_SSL_CERTFILE) and os.path.exists(REDIS_SSL_KEYFILE):
            ssl_kwargs["ssl_certfile"] = REDIS_SSL_CERTFILE
            ssl_kwargs["ssl_keyfile"] = REDIS_SSL_KEYFILE
            logger.info("Using mutual TLS authentication")

        if REDIS_SENTINEL_HOSTS:
            self._client = self._connect_via_sentinel(ssl_kwargs)
        else:
            self._client = self._connect_direct(ssl_kwargs)

        # Verify connection
        try:
            self._client.ping()
            logger.info("Successfully connected to Redis with TLS encryption")
        except redis.ConnectionError as e:
            logger.error(f"Failed to connect to Redis: {e}")
            raise

        return self._client

    def _connect_direct(self, ssl_kwargs: dict) -> redis.Redis:
        """Direct TLS connection to Redis."""
        if not REDIS_PASSWORD:
            raise ValueError(
                "REDIS_PASSWORD must be set for secure connections"
            )

        client = redis.Redis(
            host=REDIS_HOST,
            port=REDIS_PORT,
            password=REDIS_PASSWORD,
            db=REDIS_DB,
            decode_responses=True,
            socket_timeout=5,
            socket_connect_timeout=5,
            retry_on_timeout=True,
            health_check_interval=30,
            **ssl_kwargs,
        )
        logger.info(f"Connecting directly to Redis at {REDIS_HOST}:{REDIS_PORT} with TLS")
        return client

    def _connect_via_sentinel(self, ssl_kwargs: dict) -> redis.Redis:
        """Connect to Redis via Sentinel with TLS."""
        sentinel_hosts = [
            (host.strip(), REDIS_SENTINEL_PORT)
            for host in REDIS_SENTINEL_HOSTS.split(",")
            if host.strip()
        ]

        if not sentinel_hosts:
            raise ValueError("No valid Sentinel hosts configured")

        self._sentinel = Sentinel(
            sentinel_hosts,
            sentinel_kwargs={
                "password": REDIS_PASSWORD,
                **ssl_kwargs,
            },
            password=REDIS_PASSWORD,
            decode_responses=True,
            socket_timeout=5,
            **ssl_kwargs,
        )

        client = self._sentinel.master_for(
            REDIS_SENTINEL_MASTER,
            socket_timeout=5,
        )
        logger.info(f"Connected to Redis via Sentinel (master: {REDIS_SENTINEL_MASTER}) with TLS")
        return client

    def get_client(self) -> redis.Redis:
        """Get the Redis client, connecting if necessary."""
        if self._client is None:
            return self.connect()
        return self._client

    def close(self):
        """Close the Redis connection."""
        if self._client is not None:
            self._client.close()
            self._client = None
            logger.info("Redis connection closed")


class DataProtector:
    """Handles HMAC signing for data integrity verification."""

    def __init__(self, key: bytes):
        if not key:
            raise ValueError(
                "DATA_ENCRYPTION_KEY environment variable must be set"
            )
        self._key = key

    def sign_data(self, data: str) -> str:
        """Create HMAC signature for data integrity."""
        signature = hmac.new(self._key, data.encode(), hashlib.sha256).hexdigest()
        return json.dumps({"data": data, "sig": signature})

    def verify_and_extract(self, signed_data: str) -> Optional[str]:
        """Verify HMAC signature and extract data."""
        try:
            parsed = json.loads(signed_data)
            data = parsed["data"]
            signature = parsed["sig"]
            expected_sig = hmac.new(self._key, data.encode(), hashlib.sha256).hexdigest()
            if hmac.compare_digest(signature, expected_sig):
                return data
            logger.warning("Data integrity check failed - signature mismatch")
            return None
        except (json.JSONDecodeError, KeyError) as e:
            logger.error(f"Failed to verify data: {e}")
            return None


class CacheService:
    """Distributed caching service for sensitive user data."""

    def __init__(self, redis_client: SecureRedisClient, protector: DataProtector):
        self._redis = redis_client
        self._protector = protector

    def _get_redis(self) -> redis.Redis:
        return self._redis.get_client()

    # --- Session Token Management ---

    def create_session(self, user_id: str, metadata: Optional[Dict[str, Any]] = None) -> str:
        """Create a new session token for a user."""
        token = secrets.token_urlsafe(64)
        session_data = {
            "user_id": user_id,
            "created_at": datetime.utcnow().isoformat(),
            "metadata": metadata or {},
        }

        signed_data = self._protector.sign_data(json.dumps(session_data))
        key = f"{KEY_PREFIX_SESSION}{token}"

        r = self._get_redis()
        pipe = r.pipeline()
        pipe.setex(key, SESSION_TOKEN_TTL, signed_data)
        # Also maintain a user-to-sessions mapping for session management
        user_sessions_key = f"{KEY_PREFIX_SESSION}user:{user_id}"
        pipe.sadd(user_sessions_key, token)
        pipe.expire(user_sessions_key, SESSION_TOKEN_TTL)
        pipe.execute()

        logger.info(f"Session created for user {user_id}")
        return token

    def validate_session(self, token: str) -> Optional[Dict[str, Any]]:
        """Validate a session token and return session data."""
        key = f"{KEY_PREFIX_SESSION}{token}"
        r = self._get_redis()
        signed_data = r.get(key)

        if signed_data is None:
            logger.info("Session token not found or expired")
            return None

        data = self._protector.verify_and_extract(signed_data)
        if data is None:
            logger.warning("Session data integrity check failed")
            r.delete(key)
            return None

        session_data = json.loads(data)
        logger.info(f"Session validated for user {session_data['user_id']}")
        return session_data

    def revoke_session(self, token: str) -> bool:
        """Revoke a session token."""
        key = f"{KEY_PREFIX_SESSION}{token}"
        r = self._get_redis()

        # Get session data first to clean up user mapping
        signed_data = r.get(key)
        if signed_data:
            data = self._protector.verify_and_extract(signed_data)
            if data:
                session_data = json.loads(data)
                user_sessions_key = f"{KEY_PREFIX_SESSION}user:{session_data['user_id']}"
                r.srem(user_sessions_key, token)

        deleted = r.delete(key)
        # Add to blacklist to prevent reuse
        blacklist_key = f"{KEY_PREFIX_BLACKLIST}{token}"
        r.setex(blacklist_key, SESSION_TOKEN_TTL, "revoked")

        logger.info(f"Session revoked: {bool(deleted)}")
        return bool(deleted)

    def revoke_all_user_sessions(self, user_id: str) -> int:
        """Revoke all sessions for a user."""
        r = self._get_redis()
        user_sessions_key = f"{KEY_PREFIX_SESSION}user:{user_id}"
        tokens = r.smembers(user_sessions_key)

        if not tokens:
            return 0

        pipe = r.pipeline()
        for token in tokens:
            pipe.delete(f"{KEY_PREFIX_SESSION}{token}")
            pipe.setex(f"{KEY_PREFIX_BLACKLIST}{token}", SESSION_TOKEN_TTL, "revoked")
        pipe.delete(user_sessions_key)
        pipe.execute()

        count = len(tokens)
        logger.info(f"Revoked {count} sessions for user {user_id}")
        return count

    # --- API Key Management ---

    def store_api_key(self, user_id: str, key_name: str, permissions: list) -> str:
        """Generate and store an API key."""
        api_key = f"ak_{secrets.token_urlsafe(48)}"
        key_hash = hashlib.sha256(api_key.encode()).hexdigest()

        key_data = {
            "user_id": user_id,
            "key_name": key_name,
            "permissions": permissions,
            "created_at": datetime.utcnow().isoformat(),
            "key_prefix": api_key[:8],
        }

        signed_data = self._protector.sign_data(json.dumps(key_data))
        cache_key = f"{KEY_PREFIX_API_KEY}{key_hash}"

        r = self._get_redis()
        pipe = r.pipeline()
        pipe.setex(cache_key, API_KEY_TTL, signed_data)
        # Maintain user-to-keys mapping
        user_keys_key = f"{KEY_PREFIX_API_KEY}user:{user_id}"
        pipe.sadd(user_keys_key, key_hash)
        pipe.expire(user_keys_key, API_KEY_TTL)
        pipe.execute()

        logger.info(f"API key '{key_name}' created for user {user_id}")
        return api_key

    def validate_api_key(self, api_key: str) -> Optional[Dict[str, Any]]:
        """Validate an API key and return associated data."""
        key_hash = hashlib.sha256(api_key.encode()).hexdigest()
        cache_key = f"{KEY_PREFIX_API_KEY}{key_hash}"

        r = self._get_redis()
        signed_data = r.get(cache_key)

        if signed_data is None:
            logger.info("API key not found or expired")
            return None

        data = self._protector.verify_and_extract(signed_data)
        if data is None:
            logger.warning("API key data integrity check failed")
            r.delete(cache_key)
            return None

        key_data = json.loads(data)
        logger.info(f"API key validated for user {key_data['user_id']}")
        return key_data

    def revoke_api_key(self, api_key: str) -> bool:
        """Revoke an API key."""
        key_hash = hashlib.sha256(api_key.encode()).hexdigest()
        cache_key = f"{KEY_PREFIX_API_KEY}{key_hash}"

        r = self._get_redis()
        signed_data = r.get(cache_key)
        if signed_data:
            data = self._protector.verify_and_extract(signed_data)
            if data:
                key_data = json.loads(data)
                user_keys_key = f"{KEY_PREFIX_API_KEY}user:{key_data['user_id']}"
                r.srem(user_keys_key, key_hash)

        deleted = r.delete(cache_key)
        logger.info(f"API key revoked: {bool(deleted)}")
        return bool(deleted)

    # --- Refresh Token Management ---

    def store_refresh_token(self, user_id: str, session_token: str) -> str:
        """Store a refresh token associated with a session."""
        refresh_token = secrets.token_urlsafe(64)
        token_data = {
            "user_id": user_id,
            "session_token": session_token,
            "created_at": datetime.utcnow().isoformat(),
        }

        signed_data = self._protector.sign_data(json.dumps(token_data))
        key = f"{KEY_PREFIX_REFRESH_TOKEN}{refresh_token}"

        r = self._get_redis()
        r.setex(key, REFRESH_TOKEN_TTL, signed_data)

        logger.info(f"Refresh token created for user {user_id}")
        return refresh_token

    def validate_refresh_token(self, refresh_token: str) -> Optional[Dict[str, Any]]:
        """Validate a refresh token."""
        key = f"{KEY_PREFIX_REFRESH_TOKEN}{refresh_token}"
        r = self._get_redis()
        signed_data = r.get(key)

        if signed_data is None:
            return None

        data = self._protector.verify_and_extract(signed_data)
        if data is None:
            r.delete(key)
            return None

        return json.loads(data)

    def rotate_refresh_token(self, old_refresh_token: str) -> Optional[tuple]:
        """Rotate a refresh token (invalidate old, create new)."""
        token_data = self.validate_refresh_token(old_refresh_token)
        if token_data is None:
            return None

        # Invalidate old token
        old_key = f"{KEY_PREFIX_REFRESH_TOKEN}{old_refresh_token}"
        r = self._get_redis()
        r.delete(old_key)

        # Create new session and refresh token
        new_session = self.create_session(token_data["user_id"])
        new_refresh = self.store_refresh_token(token_data["user_id"], new_session)

        return new_session, new_refresh

    # --- User Profile Cache ---

    def cache_user_profile(self, user_id: str, profile_data: Dict[str, Any]) -> bool:
        """Cache user profile data (non-sensitive)."""
        key = f"{KEY_PREFIX_USER_PROFILE}{user_id}"
        r = self._get_redis()
        r.setex(key, USER_PROFILE_CACHE_TTL, json.dumps(profile_data))
        logger.info(f"User profile cached for user {user_id}")
        return True

    def get_cached_user_profile(self, user_id: str) -> Optional[Dict[str, Any]]:
        """Retrieve cached user profile."""
        key = f"{KEY_PREFIX_USER_PROFILE}{user_id}"
        r = self._get_redis()
        data = r.get(key)

        if data is None:
            return None

        return json.loads(data)

    def invalidate_user_profile_cache(self, user_id: str) -> bool:
        """Invalidate cached user profile."""
        key = f"{KEY_PREFIX_USER_PROFILE}{user_id}"
        r = self._get_redis()
        deleted = r.delete(key)
        return bool(deleted)

    # --- Rate Limiting ---

    def check_rate_limit(self, identifier: str, max_requests: int = 100) -> Dict[str, Any]:
        """Check and update rate limit for an identifier."""
        key = f"{KEY_PREFIX_RATE_LIMIT}{identifier}"
        r = self._get_redis()

        pipe = r.pipeline()
        pipe.incr(key)
        pipe.ttl(key)
        results = pipe.execute()

        current_count = results[0]
        ttl = results[1]

        # Set TTL on first request
        if ttl == -1:
            r.expire(key, RATE_LIMIT_TTL)
            ttl = RATE_LIMIT_TTL

        allowed = current_count <= max_requests
        remaining = max(0, max_requests - current_count)

        return {
            "allowed": allowed,
            "remaining": remaining,
            "limit": max_requests,
            "reset_in": ttl,
        }


