def require_service_auth(f):
    """Decorator to require service-level authentication."""
    @wraps(f)
    def decorated(*args, **kwargs):
        auth_header = request.headers.get("X-Service-Key", "")
        if not SERVICE_API_KEY or not hmac.compare_digest(auth_header, SERVICE_API_KEY):
            return jsonify({"error": "Unauthorized"}), 401
        return f(*args, **kwargs)
    return decorated


def rate_limit(max_requests: int = 100):
    """Rate limiting decorator."""
    def decorator(f):
        @wraps(f)
        def decorated(*args, **kwargs):
            identifier = request.headers.get("X-Forwarded-For", request.remote_addr)
            result = cache_service.check_rate_limit(
                f"{f.__name__}:{identifier}", max_requests
            )
            if not result["allowed"]:
                return jsonify({
                    "error": "Rate limit exceeded",
                    "retry_after": result["reset_in"],
                }), 429
            g.rate_limit_info = result
            return f(*args, **kwargs)
        return decorated
    return decorator


@app.route("/health", methods=["GET"])
def health_check():
    """Health check endpoint."""
    try:
        r = redis_client.get_client()
        r.ping()
        return jsonify({"status": "healthy", "redis": "connected"}), 200
    except Exception as e:
        logger.error(f"Health check failed: {e}")
        return jsonify({"status": "unhealthy", "redis": "disconnected"}), 503


