@rate_limit(max_requests=100)
def invalidate_user_profile(user_id):
    """Invalidate a cached user profile."""
    invalidated = cache_service.invalidate_user_profile_cache(user_id)
    return jsonify({"invalidated": invalidated}), 200


# --- Rate Limit Check Endpoint ---

@app.route("/rate-limit/check", methods=["POST"])
@require_service_auth
def check_rate_limit_endpoint():
    """Check rate limit for an identifier."""
    data = request.get_json()
    if not data or "identifier" not in data:
        return jsonify({"error": "identifier is required"}), 400

    max_requests = data.get("max_requests", 100)
    result = cache_service.check_rate_limit(data["identifier"], max_requests)
    return jsonify(result), 200


@app.errorhandler(500)
def internal_error(error):
    logger.error(f"Internal server error: {error}")
    return jsonify({"error": "Internal server error"}), 500


@app.errorhandler(404)
def not_found(error):
    return jsonify({"error": "Not found"}), 404


@app.teardown_appcontext
def teardown(exception):
    """Clean up on app context teardown."""
    pass


def shutdown():
    """Graceful shutdown."""
    logger.info("Shutting down cache service...")
    redis_client.close()


if __name__ == "__main__":
    import atexit
    atexit.register(shutdown)

    # Verify Redis connection on startup
    try:
        redis_client.connect()
        logger.info("Cache microservice starting up...")
    except Exception as e:
        logger.critical(f"Failed to connect to Redis on startup: {e}")
        raise

    app.run(
        host="0.0.0.0",
        port=int(os.environ.get("SERVICE_PORT", 8080)),
        debug=False,
    )